// src/components/Navbar.jsx
import { Link } from "react-router-dom";
import { useSelector, useDispatch } from "react-redux";
import { clearFormData } from "../redux/form/formSlice"; // Ajusta la ruta según tu estructura
import "../App.css";

const Navbar = () => {
  const dispatch = useDispatch(); // Inicializa dispatch
  const formData = useSelector((state) => state.form.formData);
  const isLoggedIn = formData.username && formData.email;

  const handleLogout = () => {
    dispatch(clearFormData());
    // Opcional: Redirigir al usuario después de logout
    // Puedes usar useNavigate de react-router-dom si lo deseas
  };

  return (
    <nav className="navbar">
      <ul className="navbar-links">
        <li><Link to="/">Home</Link></li>
        <li><Link to="/login">Login</Link></li>
        <li><Link to="/counter">Counter</Link></li>
        <li><Link to="/think">Think</Link></li>
        <li><Link to="/products">Products</Link></li>
        <li><Link to="/about">About</Link></li>
      </ul>
      <div className="navbar-user-info">
        {isLoggedIn ? (
          <div className="flex items-center space-x-4">
            <span>
              Bienvenido <strong>{formData.username}</strong> | {formData.email}
            </span>
            <button
              onClick={handleLogout}
              className="px-3 py-1 bg-blue-600 text-white rounded-md hover:bg-blue-700 transition-colors duration-200"
            >
              Logout
            </button>
          </div>
        ) : (
          "Usuario no autenticado"
        )}
      </div>
    </nav>
  );
};

export default Navbar;
